import { jsx } from 'react/jsx-runtime';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { forwardRef, useState } from 'react';
import { classNames } from '../../helpers/classnames.js';
import { useColorInteadOfStatus } from '../../types/status.js';
import { Icon } from '../Icon/Icon.js';
import { Typography } from '../Typography/Typography.js';

const Avatar = forwardRef(({ src, size = 'medium', letter, iconName = Icons.User, type, variant = 'square', className, color, onClick, hoverToCircle = false, alt, ...props }, ref) => {
    const [imageError, setImageError] = useState(false);
    const handleImageError = () => {
        setImageError(true);
    };
    let content = jsx(Icon, { className: "dsb_avatar__icon", size: size, iconName: iconName });
    // TODO: удалить при удалении пропса type (не забудь указать пропсу color дефолтное значение)
    // при удалении заменить использование avatarColor на color
    const avatarColor = useColorInteadOfStatus({ color, type }, 'Avatar');
    if (letter && size !== 'small') {
        content = (jsx(Typography, { className: classNames('dsb_avatar__title', `dsb_avatar__title--${avatarColor}`), variant: "subtitle3", children: letter }));
    }
    if (src && !imageError) {
        content = (jsx("img", { src: src, alt: alt, onError: handleImageError, className: classNames('dsb_avatar__img', `dsb_avatar__img--${size}`, `dsb_avatar__img--${variant}`) }));
    }
    return (jsx("span", { role: !src ? 'img' : undefined, onClick: onClick, "aria-label": props['aria-label'], onKeyDown: onClick
            ? event => {
                if (event.key === 'Enter' || event.key === ' ') {
                    event.preventDefault();
                    onClick();
                }
            }
            : undefined, tabIndex: onClick ? 0 : undefined, className: classNames('dsb_avatar', `dsb_avatar--${size}`, `dsb_avatar--${variant}`, `dsb_avatar--${avatarColor}`, !!onClick && 'dsb_avatar--clickable', hoverToCircle && variant === 'square' && 'dsb_avatar--hover-to-circle', className), ...props, ref: ref, "data-testid": "Avatar", children: content }));
});

export { Avatar };
